#include <bits/stdc++.h>using namespace std; // --- FAST I/O & SHORTCUTS ---using ll = long long;using vll = vector<long long>;using vi = vector<int>;using pii = pair<int, int>; // Constantsconst ll MOD = 1e9 + 7;const ll INF = 1e18; // --- LOGIC ---void solve() {    string n;    cin >> n;            ll count_0 = 0;    ll count_1 = 0;    for(auto c : n){        if(c=='0') count_0++;        else count_1++;    }    ll min_count = min(count_0, count_1);    if(min_count%2!=0) cout<<"DA\n";    else cout<<"NET\n";} // --- MAIN DRIVER ---int main() {    // Fast I/O: 10x faster input reading    ios_base::sync_with_stdio(false);    cin.tie(NULL);     int T = 1;    cin >> T; // Comment this out if problem has NO test cases    while (T--) {        solve();    }    return 0;}